using System;

// 1. Publisher
public class VideoUploader {
    // Define event using standard delegate
    public event EventHandler<string> VideoUploaded;

    public void Upload(string title) {
        Console.WriteLine($"Uploading '{title}'...");
        System.Threading.Thread.Sleep(1000);

        // Notify subscribers
        OnVideoUploaded(title);
    }

    protected virtual void OnVideoUploaded(string title) {
        VideoUploaded?.Invoke(this, title);
    }
}

// 2. Subscriber
public class Subscriber {
    public void OnVideoUploaded(object sender, string title) {
        Console.WriteLine($"Subscriber: New video '{title}' is out!");
    }
}

class Program {
    static void Main() {
        VideoUploader uploader = new VideoUploader();
        Subscriber sub = new Subscriber();

        // Subscribe
        uploader.VideoUploaded += sub.OnVideoUploaded;

        uploader.Upload("C# Tutorial");
    }
}
